39→        /// <summary>
40→        /// Builds options from environment variables.
41→        /// </summary>
42→        /// <returns>Options resolved from environment variables.</returns>
43→        public static ServiceTreeKustoOptions FromEnvironment()
44→        {
45→            var options = new ServiceTreeKustoOptions();
46→
47→            string? clusterUri = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_CLUSTER_URI");
48→            if (!string.IsNullOrWhiteSpace(clusterUri))
49→            {
50→                options.ClusterUri = clusterUri.Trim();
51→            }
52→
53→            string? database = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_DATABASE");
54→            if (!string.IsNullOrWhiteSpace(database))
55→            {
56→                options.Database = database.Trim();
57→            }
58→
59→            string? tokenScope = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_TOKEN_SCOPE");
60→            if (!string.IsNullOrWhiteSpace(tokenScope))
61→            {
62→                options.TokenScope = tokenScope.Trim();
63→            }
64→
65→            string? maxBatchSize = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_MAX_BATCH");
66→            if (!string.IsNullOrWhiteSpace(maxBatchSize) && int.TryParse(maxBatchSize, out var parsed))
67→            {
68→                options.MaxBatchSize = parsed;
69→            }
70→
71→            string? hierarchyTable = Environment.GetEnvironmentVariable("SERVICETREE_KUSTO_HIERARCHY_TABLE");
72→            if (!string.IsNullOrWhiteSpace(hierarchyTable))
73→            {
74→                options.HierarchyTableName = hierarchyTable.Trim();
75→            }
76→
77→            return options;
78→        }
79→    }
