private string BuildQueryByIds(IReadOnlyList<string> ids)
{
    var builder = new StringBuilder();

    if (this.kustoOptions.UseOrganizationFunction
        && !string.IsNullOrWhiteSpace(this.kustoOptions.OrganizationFunctionName))
    {
        var functionName = this.NormalizeIdentifier(this.kustoOptions.OrganizationFunctionName);
        builder.AppendLine("let Organizations = datatable(OrganizationId:string)[");
        builder.Append(string.Join(", ", ids.Select(id => $"'{EscapeKustoString(id)}'")));
        builder.AppendLine("];");
        builder.AppendLine($"{functionName}(Organizations)");
        builder.AppendLine("| project");
        builder.AppendLine("    InternalId = toint(column_ifexists(\"InternalId\", column_ifexists(\"OrganizationInternalId\", 0))),");
        builder.AppendLine("    Id = tostring(column_ifexists(\"OrganizationId\", \"\")),");
        builder.AppendLine("    Level = tostring(column_ifexists(\"Level\", \"\")),");
        builder.AppendLine("    Name = tostring(column_ifexists(\"OrganizationName\", column_ifexists(\"Name\", \"\"))),");
        builder.AppendLine("    Organization = tostring(column_ifexists(\"Organization\", \"\")),");
        builder.AppendLine("    ParentOrganizationId = tostring(column_ifexists(\"ParentOrganizationId\", \"\"))");
    }
    else
    {
        var tableName = this.NormalizeIdentifier(this.kustoOptions.TableName);
        var idColumn = this.NormalizeIdentifier(this.kustoOptions.IdColumnName);
        builder.AppendLine("let ids = datatable(TargetId:string)[");
        builder.Append(string.Join(", ", ids.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
        builder.AppendLine("];");
        builder.AppendLine($"{tableName}");
        builder.AppendLine($"| where tolower({idColumn}) in (ids)");
        builder.AppendLine("| project");
        builder.AppendLine("    InternalId = toint(column_ifexists(\"InternalId\", column_ifexists(\"OrganizationInternalId\", 0))),");
        builder.AppendLine($"    Id = tostring({idColumn}),");
        builder.AppendLine("    Level = tostring(column_ifexists(\"Level\", \"\")),");
        builder.AppendLine("    Name = tostring(column_ifexists(\"OrganizationName\", column_ifexists(\"Name\", \"\"))),");
        builder.AppendLine("    Organization = tostring(column_ifexists(\"Organization\", \"\")),");
        builder.AppendLine("    ParentOrganizationId = tostring(column_ifexists(\"ParentOrganizationId\", \"\"))");
    }

    return builder.ToString();
}

